  glossary:[
    {term:"Catenary",def:"The overhead wire system supplying electrical power to trains. Indian Railways standard: 25 kV AC, 50 Hz. The wire is suspended by steel masts every 50-70 meters along the track."},
    {term:"Pantograph",def:"Spring-loaded arm on the train's roof collecting current from the overhead catenary wire. Must maintain constant contact pressure at all speeds. Contact strip (carbon or copper-graphite) is a consumable component."},
    {term:"Traction Motor",def:"Electric motor driving the train's wheels. AC induction or permanent magnet type, 200-400 kW each. Controlled by IGBT/SiC inverters for variable speed. Operates in reverse as a generator during regenerative braking."},
    {term:"CBTC",def:"Communications-Based Train Control — signaling system using continuous radio communication between train and control center. Enables moving block (dynamic safe spacing), 90-second headways, and automated train operation (GoA 2-4)."},
    {term:"GoA (Grade of Automation)",def:"GoA 1: manual driving with ATP. GoA 2: automatic driving, driver supervises. GoA 3: driverless with attendant. GoA 4: fully unattended. Delhi Metro: GoA 2 on newer lines."},
    {term:"Regenerative Braking",def:"Traction motors operate as generators during deceleration, converting kinetic energy to electricity fed back to the power grid. Recovers 30-45% of traction energy in metro systems."},
    {term:"Kavach",def:"Indian Railways' indigenous Automatic Train Protection system. Prevents signal violations, automatically brakes for danger, and enables train-to-train communication. 50-70% cheaper than European ETCS."},
    {term:"Vande Bharat",def:"India's indigenous semi-high-speed trainset. 160 km/h design speed. Chair car, automatic doors, bio-toilets, regenerative braking. Manufactured at ICF Chennai. 100+ in service, 400+ planned."},
    {term:"DFC",def:"Dedicated Freight Corridor — separate rail line exclusively for freight. Double-stack containers, 25-tonne axle load, 100 km/h. Eastern and Western DFCs under construction across India."},
    {term:"Bogie",def:"Wheel truck assembly: wheelsets + suspension + motors + brakes. Primary suspension absorbs track vibrations; secondary (air spring) suspension provides passenger comfort. Self-steering via conical wheel profile."},
  ],
